229→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
230→            return;
231→          case 's':
232→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
233→            return;
234→          case 'r':
235→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
236→            return;
237→          case 'd':
238→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
239→            return;
240→          case 'n':
241→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
242→            return;
243→          case 'c':
244→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
245→            return;
246→          case 'l':
247→            editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
248→            return;
