251→            editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
252→            return;
253→        }
254→      }
255→
256→      tool.onKeyDown(e);
257→    };
258→
259→    const handleKeyUp = (e) => {
260→      if (isTypingTarget(e.target)) return;
261→
262→      if (e.key === ' ') {
263→        spaceHeld.current = false;
264→      }
265→    };
