267→    window.addEventListener('keydown', handleKeyDown);
268→    window.addEventListener('keyup', handleKeyUp);
269→    return () => {
270→      window.removeEventListener('keydown', handleKeyDown);
271→      window.removeEventListener('keyup', handleKeyUp);
272→    };
273→  }, [beginPaste, cancelPaste, copySelection, cutSelection, pastePreview?.active, tool, editorDispatch, viewMode]);
274→
275→  // Prevent default context menu on SVG
276→  useEffect(() => {
277→    const svg = svgRef.current;
278→    if (!svg) return;
